#include <iostream>
#include <vector>
#include <atomic>

class Counter {
private:
    static std::atomic<int> g_total_instances;

public:
    Counter() { g_total_instances.operator++(); }
    ~Counter() { g_total_instances.operator--(); }

    static int get_total_num_active_counters() { return g_total_instances.load(); }
};

std::atomic<int> Counter::g_total_instances(0);

int main() {
    std::cout << "Beginning of program execution." << std::endl;
    std::cout << "Active counter count at start: " << Counter::get_total_num_active_counters() << std::endl;

    Counter first_counter_obj;
    {
        Counter second_counter_obj;
        std::vector<Counter> some_vector_of_counters(2);
        std::cout << "Count with 4 objects: " << Counter::get_total_num_active_counters() << std::endl;
    }
    std::cout << "Count after scope exit (1 object): " << Counter::get_total_num_active_counters() << std::endl;

    Counter* dynamically_allocated_counter = new Counter();
    std::cout << "Count with dynamically allocated object (2 objects): " << Counter::get_total_num_active_counters() << std::endl;

    delete dynamically_allocated_counter;
    std::cout << "Count after deleting dynamically allocated object (1 object): " << Counter::get_total_num_active_counters() << std::endl;

    std::cout << "End of program execution." << std::endl;
    return 0;
}
